 1→package mem
 2→
 3→import (
 4→	"context"
 5→	"sync"
 6→
 7→	api "github.com/ALRubinger/aileron/core/api/gen"
 8→	"github.com/ALRubinger/aileron/core/store"
 9→)
10→
11→// IntentStore is a thread-safe in-memory implementation of store.IntentStore.
12→type IntentStore struct {
13→	mu      sync.RWMutex
14→	intents map[string]api.IntentEnvelope
15→}
16→
17→// NewIntentStore returns an empty in-memory intent store.
18→func NewIntentStore() *IntentStore {
19→	return &IntentStore{intents: make(map[string]api.IntentEnvelope)}
20→}
21→
22→func (s *IntentStore) Create(_ context.Context, intent api.IntentEnvelope) error {
23→	s.mu.Lock()
24→	defer s.mu.Unlock()
25→	s.intents[intent.IntentId] = intent
26→	return nil
27→}
28→
29→func (s *IntentStore) Get(_ context.Context, intentID string) (api.IntentEnvelope, error) {
30→	s.mu.RLock()
31→	defer s.mu.RUnlock()
32→	intent, ok := s.intents[intentID]
33→	if !ok {
34→		return api.IntentEnvelope{}, &store.ErrNotFound{Entity: "intent", ID: intentID}
35→	}
36→	return intent, nil
37→}
38→
39→func (s *IntentStore) List(_ context.Context, filter store.IntentFilter) ([]api.IntentEnvelope, error) {
40→	s.mu.RLock()
41→	defer s.mu.RUnlock()
42→	var result []api.IntentEnvelope
43→	for _, intent := range s.intents {
44→		if filter.WorkspaceID != "" && intent.WorkspaceId != filter.WorkspaceID {
45→			continue
46→		}
47→		if filter.Status != nil && intent.Status != *filter.Status {
48→			continue
49→		}
50→		if filter.AgentID != "" && intent.Agent.Id != filter.AgentID {
51→			continue
52→		}
53→		result = append(result, intent)
54→	}
55→	return result, nil
56→}
57→
58→func (s *IntentStore) Update(_ context.Context, intent api.IntentEnvelope) error {
59→	s.mu.Lock()
60→	defer s.mu.Unlock()
61→	if _, ok := s.intents[intent.IntentId]; !ok {
62→		return &store.ErrNotFound{Entity: "intent", ID: intent.IntentId}
63→	}
64→	s.intents[intent.IntentId] = intent
65→	return nil
66→}
