 1→import { PUBLIC_API_BASE } from '$env/static/public';
 2→
 3→const API_BASE = PUBLIC_API_BASE;
 4→
 5→async function apiFetch(path: string, options?: RequestInit) {
 6→	const res = await fetch(`${API_BASE}${path}`, {
 7→		headers: { 'Content-Type': 'application/json' },
 8→		...options
 9→	});
10→	if (res.status === 204) return null;
11→	if (!res.ok) {
12→		const err = await res.json().catch(() => ({ error: { message: res.statusText } }));
13→		throw new Error(err.error?.message || res.statusText);
14→	}
15→	return res.json();
16→}
17→
18→export async function listApprovals(workspaceId = 'default') {
19→	return apiFetch(`/v1/approvals?workspace_id=${workspaceId}`);
20→}
21→
22→export async function getApproval(approvalId: string) {
23→	return apiFetch(`/v1/approvals/${approvalId}`);
24→}
25→
26→export async function approveRequest(approvalId: string, comment?: string) {
27→	return apiFetch(`/v1/approvals/${approvalId}/approve`, {
28→		method: 'POST',
29→		body: JSON.stringify({ comment })
30→	});
31→}
32→
33→export async function denyRequest(approvalId: string, reason: string, comment?: string) {
34→	return apiFetch(`/v1/approvals/${approvalId}/deny`, {
35→		method: 'POST',
36→		body: JSON.stringify({ reason, comment })
37→	});
38→}
