// Package model defines shared domain types used across the control plane.
//
// These types are the canonical Go representations of the structures defined
// in the OpenAPI specification. All SPI packages import from here rather than
// defining their own copies.
package model

import "time"

// ActorRef identifies who or what performed an action.
type ActorRef struct {
	ID          string
	Type        ActorType
	DisplayName string
}

// ActorType classifies the actor.
type ActorType string

const (
	ActorTypeAgent            ActorType = "agent"
	ActorTypeHuman            ActorType = "human"
	ActorTypeService          ActorType = "service"
	ActorTypeConnectorRuntime ActorType = "connector_runtime"
)

// ActionTarget describes the resource an action operates on.
type ActionTarget struct {
	Kind        string
	ID          string
	DisplayName string
}

// ActionIntent describes what an agent intends to do.
type ActionIntent struct {
	// Type is a dot-namespaced action identifier, e.g. "payment.charge",
	// "git.pull_request.create", "calendar.event.create".
	Type          string
	Summary       string
	Justification string
	Target        ActionTarget
	Domain        DomainAction
	Metadata      map[string]any
}

// DomainAction carries action-type-specific fields.
// Exactly one field should be populated, corresponding to the ActionIntent.Type prefix.
type DomainAction struct {
	Git         *GitAction
	Deploy      *DeployAction
	Cloud       *CloudAction
	Email       *EmailAction
	Calendar    *CalendarAction
	Payment     *PaymentAction
	Procurement *ProcurementAction
}

// Money represents an amount in minor units (e.g. cents) with a currency code.
type Money struct {
	Amount   int64
	Currency string // ISO 4217, e.g. "USD"
}

// GitAction carries git/source-control-specific intent fields.
type GitAction struct {
	Provider       string // "github", "gitlab", "bitbucket", "custom"
	Repository     string
	Branch         string
	BaseBranch     string
	CommitSHAs     []string
	FilesChanged   []string
	PRTitle        string
	PRBody         string
	Labels         []string
	Reviewers      []string
	ChecksRequired []string
}

// DeployAction carries deployment-specific intent fields.
type DeployAction struct {
	Provider            string // "kubernetes", "vercel", "netlify", etc.
	Service             string
	Environment         string
	ArtifactRef         string
	ImageRef            string
	Cluster             string
	Namespace           string
	Strategy            string // "rolling", "blue_green", "canary", "replace", "custom"
	RollbackSupported   bool
	ChangeTicketID      string
	MaintenanceWindowID string
}

// CloudAction carries cloud-resource-specific intent fields.
type CloudAction struct {
	Provider      string // "aws", "gcp", "azure", "cloudflare", "custom"
	AccountID     string
	Region        string
	ResourceType  string
	ResourceID    string
	Operation     string
	EstimatedCost *Money
	Tags          map[string]string
}

// EmailAction carries email-specific intent fields.
type EmailAction struct {
	From        *Recipient
	To          []Recipient
	CC          []Recipient
	BCC         []Recipient
	Subject     string
	BodyText    string
	BodyHTML    string
	Attachments []AttachmentRef
	ThreadRef   string
	SendMode    string // "send_now", "draft_only"
}

// Recipient identifies an email participant.
type Recipient struct {
	Name  string
	Email string
}

// AttachmentRef references a file attachment.
type AttachmentRef struct {
	Name       string
	MIMEType   string
	URL        string
	StorageRef string
}

// CalendarAction carries calendar-specific intent fields.
type CalendarAction struct {
	Provider       string // "google_calendar", "outlook", "custom"
	Title          string
	Description    string
	Attendees      []CalendarAttendee
	StartTime      *time.Time
	EndTime        *time.Time
	Timezone       string
	Location       string
	ConferenceType string // "none", "google_meet", "zoom", "teams", "custom"
	CalendarID     string
	Visibility     string // "default", "public", "private"
}

// CalendarAttendee is a participant in a calendar event.
type CalendarAttendee struct {
	Name     string
	Email    string
	Optional bool
}

// PaymentAction carries payment-specific intent fields.
type PaymentAction struct {
	VendorName                   string
	VendorID                     string
	Amount                       Money
	MerchantCategory             string
	BudgetCode                   string
	FundingSourceID              string
	PaymentInstrumentPreference  string // "virtual_card", "ach", "wallet", "network_proxy", "unspecified"
	Beneficiary                  *PaymentBeneficiary
	LineItems                    []LineItem
	Renewal                      bool
	ContractTerm                 string
	RecurringInterval            string // "none", "monthly", "quarterly", "annual"
	MerchantReference            string
}

// PaymentBeneficiary identifies the person or team benefiting from a payment.
type PaymentBeneficiary struct {
	Name       string
	Email      string
	Department string
}

// LineItem is a single item in a payment or procurement request.
type LineItem struct {
	Description string
	Quantity    int
	UnitAmount  Money
	SKU         string
}

// ProcurementAction carries procurement-specific intent fields.
type ProcurementAction struct {
	RequestType            string // "software", "travel", "equipment", "contractor", "services", "other"
	VendorName             string
	AmountEstimate         *Money
	Justification          string
	Requestor              string
	CostCenter             string
	LegalReviewRequired    bool
	SecurityReviewRequired bool
	LineItems              []LineItem
}

// IntentContext carries runtime context used by policy rules.
type IntentContext struct {
	Environment      string
	SourcePlatform   string
	SourceSessionID  string
	SourceTraceID    string
	IPAddress        string
	UserPresent      bool
	RiskHints        []string
	TemporaryGrantID string
}

// Disposition is the outcome of policy evaluation.
type Disposition string

const (
	DispositionAllow               Disposition = "allow"
	DispositionAllowModified       Disposition = "allow_modified"
	DispositionRequireApproval     Disposition = "require_approval"
	DispositionDeny                Disposition = "deny"
	DispositionRequireMoreEvidence Disposition = "require_more_evidence"
)

// RiskLevel is the assessed risk of an intent.
type RiskLevel string

const (
	RiskLevelLow      RiskLevel = "low"
	RiskLevelMedium   RiskLevel = "medium"
	RiskLevelHigh     RiskLevel = "high"
	RiskLevelCritical RiskLevel = "critical"
)

// Decision is the output of policy evaluation.
type Decision struct {
	Disposition     Disposition
	RiskLevel       RiskLevel
	MatchedPolicies []PolicyMatch
	DenialReason    string
}

// PolicyMatch records which policy rule produced a decision.
type PolicyMatch struct {
	PolicyID      string
	PolicyVersion int
	RuleID        string
	Explanation   string
}

// EventType identifies the kind of audit event.
type EventType string

const (
	EventTypeIntentSubmitted    EventType = "intent.submitted"
	EventTypePolicyEvaluated    EventType = "policy.evaluated"
	EventTypeApprovalRequested  EventType = "approval.requested"
	EventTypeApprovalApproved   EventType = "approval.approved"
	EventTypeApprovalDenied     EventType = "approval.denied"
	EventTypeApprovalModified   EventType = "approval.modified"
	EventTypeGrantIssued        EventType = "grant.issued"
	EventTypeGrantRevoked       EventType = "grant.revoked"
	EventTypeExecutionStarted   EventType = "execution.started"
	EventTypeExecutionSucceeded EventType = "execution.succeeded"
	EventTypeExecutionFailed    EventType = "execution.failed"

	// Gateway tool call events.
	EventTypeToolCallIntercepted    EventType = "tool.call.intercepted"
	EventTypeToolCallForwarded      EventType = "tool.call.forwarded"
	EventTypeToolCallDenied         EventType = "tool.call.denied"
	EventTypeToolCallPendingApproval EventType = "tool.call.pending_approval"
)

// Package store defines persistence interfaces for the control plane.
//
// These interfaces decouple the API handlers from the storage backend.
// The in-memory implementations (in the mem sub-package) are suitable for
// development and testing. Production deployments swap in Postgres-backed
// implementations without changing business logic.
package store

import (
	"context"

	api "github.com/ALRubinger/aileron/core/api/gen"
)

// IntentStore persists and retrieves action intents.
type IntentStore interface {
	Create(ctx context.Context, intent api.IntentEnvelope) error
	Get(ctx context.Context, intentID string) (api.IntentEnvelope, error)
	List(ctx context.Context, filter IntentFilter) ([]api.IntentEnvelope, error)
	Update(ctx context.Context, intent api.IntentEnvelope) error
}

// IntentFilter scopes an intent list query.
type IntentFilter struct {
	WorkspaceID string
	Status      *api.IntentStatus
	AgentID     string
	PageSize    int
	PageToken   string
}

// ApprovalStore persists and retrieves approval requests.
type ApprovalStore interface {
	Create(ctx context.Context, approval api.Approval) error
	Get(ctx context.Context, approvalID string) (api.Approval, error)
	List(ctx context.Context, filter ApprovalFilter) ([]api.Approval, error)
	Update(ctx context.Context, approval api.Approval) error
}

// ApprovalFilter scopes an approval list query.
type ApprovalFilter struct {
	WorkspaceID string
	Status      *api.ApprovalStatus
	IntentID    string
	PageSize    int
	PageToken   string
}

// PolicyStore persists and retrieves policy definitions.
type PolicyStore interface {
	Create(ctx context.Context, policy api.Policy) error
	Get(ctx context.Context, policyID string) (api.Policy, error)
	List(ctx context.Context, filter PolicyFilter) ([]api.Policy, error)
	Update(ctx context.Context, policy api.Policy) error
}

// PolicyFilter scopes a policy list query.
type PolicyFilter struct {
	WorkspaceID string
	Status      *api.PolicyStatus
	PageSize    int
	PageToken   string
}

// GrantStore persists and retrieves execution grants.
type GrantStore interface {
	Create(ctx context.Context, grant api.ExecutionGrant) error
	Get(ctx context.Context, grantID string) (api.ExecutionGrant, error)
	Update(ctx context.Context, grant api.ExecutionGrant) error
}

// ExecutionStore persists and retrieves execution records.
type ExecutionStore interface {
	Create(ctx context.Context, execution api.Execution) error
	Get(ctx context.Context, executionID string) (api.Execution, error)
	Update(ctx context.Context, execution api.Execution) error
}

// ConnectorStore persists and retrieves connector registrations.
type ConnectorStore interface {
	Create(ctx context.Context, connector api.Connector) error
	Get(ctx context.Context, connectorID string) (api.Connector, error)
	List(ctx context.Context, filter ConnectorFilter) ([]api.Connector, error)
	Update(ctx context.Context, connector api.Connector) error
}

// ConnectorFilter scopes a connector list query.
type ConnectorFilter struct {
	WorkspaceID string
	Type        *api.ConnectorType
	PageSize    int
	PageToken   string
}

// CredentialStore persists and retrieves credential references (not secrets).
type CredentialStore interface {
	Create(ctx context.Context, cred api.CredentialReference) error
	Get(ctx context.Context, credentialID string) (api.CredentialReference, error)
	List(ctx context.Context, filter CredentialFilter) ([]api.CredentialReference, error)
}

// CredentialFilter scopes a credential list query.
type CredentialFilter struct {
	WorkspaceID string
	PageSize    int
	PageToken   string
}

// FundingSourceStore persists and retrieves funding sources.
type FundingSourceStore interface {
	Create(ctx context.Context, fs api.FundingSource) error
	Get(ctx context.Context, fundingSourceID string) (api.FundingSource, error)
	List(ctx context.Context, filter FundingSourceFilter) ([]api.FundingSource, error)
}

// FundingSourceFilter scopes a funding source list query.
type FundingSourceFilter struct {
	WorkspaceID string
	PageSize    int
	PageToken   string
}

// MCPServerStore persists and retrieves MCP server configurations.
type MCPServerStore interface {
	Create(ctx context.Context, server api.MCPServerConfig) error
	Get(ctx context.Context, serverID string) (api.MCPServerConfig, error)
	List(ctx context.Context, filter MCPServerFilter) ([]api.MCPServerConfig, error)
	Update(ctx context.Context, server api.MCPServerConfig) error
	Delete(ctx context.Context, serverID string) error
}

// MCPServerFilter scopes an MCP server list query.
type MCPServerFilter struct {
	Status   *api.MCPServerConfigStatus
	PageSize int
}

// ErrNotFound is returned when a requested entity does not exist.
type ErrNotFound struct {
	Entity string
	ID     string
}

func (e *ErrNotFound) Error() string {
	return e.Entity + " not found: " + e.ID
}

// Package config loads and validates YAML configuration for the Aileron
// MCP gateway.
//
// A configuration file defines the set of downstream MCP servers that
// Aileron proxies, along with optional policy mappings and environment
// variable overrides. Environment values prefixed with "vault://" are
// resolved from the Aileron vault at launch time via [ResolveVaultEnv].
package config

import (
	"fmt"
	"os"
	"regexp"

	"gopkg.in/yaml.v3"
)

// namePattern matches valid downstream server names: starts with a letter,
// followed by zero or more alphanumeric characters or underscores.
var namePattern = regexp.MustCompile(`^[a-zA-Z][a-zA-Z0-9_]*$`)

// vaultPrefix is the sentinel prefix for environment variable values that
// should be resolved from the vault.
const vaultPrefix = "vault://"

// Execution mode constants for downstream servers.
const (
	// ModeLocal runs the MCP server as a local subprocess (stdio transport).
	// This is the default when Mode is omitted.
	ModeLocal = "local"

	// ModeRemote connects to a centrally-managed MCP server over HTTP
	// (Streamable HTTP transport). The control plane manages the server
	// instance; no local command is needed.
	ModeRemote = "remote"
)

// Config is the top-level Aileron gateway configuration.
type Config struct {
	// Version is the config file format version. Currently "1".
	Version string `yaml:"version"`

	// WorkspaceID is the default workspace for policy evaluation.
	// Defaults to "default" if empty.
	WorkspaceID string `yaml:"workspace_id"`

	// DownstreamServers lists the MCP servers that Aileron proxies.
	DownstreamServers []DownstreamServer `yaml:"downstream_servers"`
}

// DownstreamServer defines a single downstream MCP server.
type DownstreamServer struct {
	// Name is a unique identifier for this server, used as tool name prefix.
	// Must be a valid identifier (alphanumeric + underscore, no spaces).
	Name string `yaml:"name"`

	// Mode is the execution mode: "local" (default) or "remote".
	// Local servers are spawned as subprocesses; remote servers are accessed
	// over HTTP via the control plane. Omitting Mode defaults to "local".
	Mode string `yaml:"mode,omitempty"`

	// Command is the command to execute, including any arguments.
	// Required for local mode; must be empty for remote mode.
	// Example: ["npx", "-y", "@modelcontextprotocol/server-github"]
	Command []string `yaml:"command"`

	// Env is environment variables to set for the subprocess.
	// Values prefixed with "vault://" are resolved from the Aileron vault at launch time.
	Env map[string]string `yaml:"env"`

	// PolicyMapping configures how this server's tools map to policy evaluation.
	PolicyMapping *PolicyMapping `yaml:"policy_mapping,omitempty"`
}

// PolicyMapping configures how tools from a downstream server map to the
// policy engine's action type namespace.
type PolicyMapping struct {
	// ToolPrefix maps tool calls to the action type namespace.
	// For example, with tool_prefix "git", a tool "create_pull_request"
	// becomes action type "git.create_pull_request" for policy evaluation.
	ToolPrefix string `yaml:"tool_prefix"`
}

// Load reads a YAML configuration file from path, unmarshals it, and
// validates the result. It returns the parsed Config or the first error
// encountered.
func Load(path string) (*Config, error) {
	data, err := os.ReadFile(path)
	if err != nil {
		return nil, fmt.Errorf("reading config file: %w", err)
	}

	var cfg Config
	if err := yaml.Unmarshal(data, &cfg); err != nil {
		return nil, fmt.Errorf("parsing config file: %w", err)
	}

	if err := cfg.Validate(); err != nil {
		return nil, err
	}

	return &cfg, nil
}

// LoadFromEnvOrDefault loads configuration using the following precedence:
//
//  1. The path in the AILERON_CONFIG environment variable.
//  2. "aileron.yaml" in the current working directory.
//  3. An empty Config (no downstream servers) — this is not an error; it
//     allows the gateway to start with no downstream servers configured.
func LoadFromEnvOrDefault() (*Config, error) {
	if path := os.Getenv("AILERON_CONFIG"); path != "" {
		return Load(path)
	}

	const defaultFile = "aileron.yaml"
	if _, err := os.Stat(defaultFile); err == nil {
		return Load(defaultFile)
	}

	return &Config{}, nil
}

// Validate checks the configuration for structural correctness. It returns
// a descriptive error for the first validation failure found.
func (c *Config) Validate() error {
	if c.Version != "" && c.Version != "1" {
		return fmt.Errorf("unsupported config version %q: must be \"1\"", c.Version)
	}

	seen := make(map[string]bool, len(c.DownstreamServers))
	for i, ds := range c.DownstreamServers {
		if ds.Name == "" {
			return fmt.Errorf("downstream_servers[%d]: name must not be empty", i)
		}
		if !namePattern.MatchString(ds.Name) {
			return fmt.Errorf("downstream_servers[%d]: name %q must match %s", i, ds.Name, namePattern.String())
		}
		if seen[ds.Name] {
			return fmt.Errorf("downstream_servers[%d]: duplicate name %q", i, ds.Name)
		}
		seen[ds.Name] = true

		// Normalize and validate mode.
		mode := ds.Mode
		if mode == "" {
			mode = ModeLocal
		}
		if mode != ModeLocal && mode != ModeRemote {
			return fmt.Errorf("downstream_servers[%d] (%s): invalid mode %q: must be %q or %q", i, ds.Name, ds.Mode, ModeLocal, ModeRemote)
		}

		// Local servers require a command; remote servers must not have one.
		if mode == ModeLocal && len(ds.Command) == 0 {
			return fmt.Errorf("downstream_servers[%d] (%s): command must not be empty for local mode", i, ds.Name)
		}
		if mode == ModeRemote && len(ds.Command) > 0 {
			return fmt.Errorf("downstream_servers[%d] (%s): command must be empty for remote mode", i, ds.Name)
		}
	}

	return nil
}

// ResolveVaultEnv returns a copy of env with all "vault://"-prefixed values
// resolved through the provided vaultGet function. Non-vault values are
// copied unchanged. The original map is never modified.
func ResolveVaultEnv(env map[string]string, vaultGet func(path string) ([]byte, error)) (map[string]string, error) {
	resolved := make(map[string]string, len(env))

	for k, v := range env {
		if len(v) > len(vaultPrefix) && v[:len(vaultPrefix)] == vaultPrefix {
			vaultPath := v[len(vaultPrefix):]
			secret, err := vaultGet(vaultPath)
			if err != nil {
				return nil, fmt.Errorf("resolving vault env %q (path %q): %w", k, vaultPath, err)
			}
			resolved[k] = string(secret)
		} else {
			resolved[k] = v
		}
	}

	return resolved, nil
}

// Package app wires together the Aileron control plane components and exposes
// them as an http.Handler. It is imported by the standalone server binary and
// the MCP server's embedded mode.
package app

import (
	"context"
	"log/slog"
	"net/http"
	"os"
	"time"

	api "github.com/ALRubinger/aileron/core/api/gen"
	"github.com/ALRubinger/aileron/core/approval"
	"github.com/ALRubinger/aileron/core/connector"
	googlecalendar "github.com/ALRubinger/aileron/core/connector/calendar/google"
	"github.com/ALRubinger/aileron/core/connector/git/github"
	"github.com/ALRubinger/aileron/core/connector/payments/stripe"
	"github.com/ALRubinger/aileron/core/notify"
	"github.com/ALRubinger/aileron/core/policy"
	mcpreg "github.com/ALRubinger/aileron/core/registry"
	"github.com/ALRubinger/aileron/core/store/mem"
	"github.com/ALRubinger/aileron/core/vault"
	"github.com/google/uuid"
)

// NewHandler creates a fully-wired Aileron control plane HTTP handler with
// in-memory stores, seeded policies, and registered connectors.
func NewHandler(log *slog.Logger) (http.Handler, error) {
	ctx := context.Background()

	// --- In-memory stores ---
	intentStore := mem.NewIntentStore()
	approvalStore := mem.NewApprovalStore()
	policyStore := mem.NewPolicyStore()
	grantStore := mem.NewGrantStore()
	executionStore := mem.NewExecutionStore()
	connectorStore := mem.NewConnectorStore()
	mcpServerStore := mem.NewMCPServerStore()
	credentialStore := mem.NewCredentialStore()
	fundingSourceStore := mem.NewFundingSourceStore()
	traceStore := mem.NewTraceStore()

	// --- Connector registry ---
	registry := connector.NewRegistry()
	registry.Register(ctx, stripe.New())
	registry.Register(ctx, googlecalendar.New())
	registry.Register(ctx, github.New())

	// --- Vault ---
	v := vault.NewMemVault()
	if token := os.Getenv("GITHUB_TOKEN"); token != "" {
		v.Put(ctx, "connectors/github/default", []byte(token), vault.Metadata{
			Type: "api_key",
			Labels: map[string]string{
				"connector": "github",
			},
		})
		log.Info("seeded GitHub token into vault")
	}

	// --- Policy engine ---
	policyEngine := policy.NewRuleEngine(policyStore)

	if err := policy.SeedPolicies(ctx, policyStore); err != nil {
		return nil, err
	}
	log.Info("seeded default policies")

	// --- Approval orchestrator ---
	idGen := func() string { return uuid.New().String() }
	orchestrator := approval.NewInMemoryOrchestrator(approvalStore, idGen)

	// --- MCP Registry client ---
	registryClient := mcpreg.NewClient(nil, log)
	if interval := os.Getenv("REGISTRY_REFRESH_INTERVAL"); interval != "" {
		if d, err := time.ParseDuration(interval); err == nil {
			registryClient = registryClient.WithRefreshInterval(d)
			log.Info("registry refresh interval overridden", "interval", d)
		} else {
			log.Warn("invalid REGISTRY_REFRESH_INTERVAL, using default", "value", interval, "error", err)
		}
	}
	registryClient.Start(ctx)

	// --- Notifier ---
	notifier := notify.NewLogNotifier(log)

	// --- HTTP handler ---
	mux := http.NewServeMux()

	server := &apiServer{
		log:            log,
		registry:       registry,
		policyEngine:   policyEngine,
		orchestrator:   orchestrator,
		vault:          v,
		notifier:       notifier,
		intents:        intentStore,
		approvals:      approvalStore,
		policies:       policyStore,
		grants:         grantStore,
		executions:     executionStore,
		connectors:     connectorStore,
		mcpServers:     mcpServerStore,
		registryClient: registryClient,
		credentials:    credentialStore,
		fundingSources: fundingSourceStore,
		traces:         traceStore,
		newID:          idGen,
	}
	api.HandlerFromMux(server, mux)

	registerDocsRoutes(mux)

	// Middleware chain: CORS -> request ID -> logging -> routes.
	var handler http.Handler = mux
	handler = loggingMiddleware(log, handler)
	handler = requestIDMiddleware(handler)
	handler = corsMiddleware(handler)

	return handler, nil
}

package app

import (
	"context"
	"crypto/rand"
	"encoding/hex"
	"log/slog"
	"net/http"
	"time"
)

type contextKey int

const requestIDKey contextKey = iota

// RequestID returns the request ID from the context, or empty string if none.
func RequestID(ctx context.Context) string {
	id, _ := ctx.Value(requestIDKey).(string)
	return id
}

// requestIDMiddleware injects a unique request ID into each request context
// and sets it on the response. If the client sends X-Request-ID, it is reused.
func requestIDMiddleware(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		id := r.Header.Get("X-Request-ID")
		if id == "" {
			id = generateID()
		}
		w.Header().Set("X-Request-ID", id)
		ctx := context.WithValue(r.Context(), requestIDKey, id)
		next.ServeHTTP(w, r.WithContext(ctx))
	})
}

// loggingMiddleware logs each request with method, path, status, and duration.
func loggingMiddleware(log *slog.Logger, next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		start := time.Now()
		sw := &statusWriter{ResponseWriter: w, status: http.StatusOK}
		next.ServeHTTP(sw, r)
		log.InfoContext(r.Context(), "request",
			"method", r.Method,
			"path", r.URL.Path,
			"status", sw.status,
			"duration_ms", time.Since(start).Milliseconds(),
			"request_id", RequestID(r.Context()),
		)
	})
}

// statusWriter wraps http.ResponseWriter to capture the status code.
type statusWriter struct {
	http.ResponseWriter
	status      int
	wroteHeader bool
}

func (w *statusWriter) WriteHeader(code int) {
	if !w.wroteHeader {
		w.status = code
		w.wroteHeader = true
	}
	w.ResponseWriter.WriteHeader(code)
}

func (w *statusWriter) Write(b []byte) (int, error) {
	if !w.wroteHeader {
		w.wroteHeader = true
	}
	return w.ResponseWriter.Write(b)
}

// corsMiddleware adds permissive CORS headers for development. Production
// deployments should restrict AllowedOrigins via configuration.
func corsMiddleware(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		w.Header().Set("Access-Control-Allow-Origin", "*")
		w.Header().Set("Access-Control-Allow-Methods", "GET, POST, PATCH, DELETE, OPTIONS")
		w.Header().Set("Access-Control-Allow-Headers", "Authorization, Content-Type, X-Request-ID")
		w.Header().Set("Access-Control-Expose-Headers", "X-Request-ID")

		if r.Method == http.MethodOptions {
			w.WriteHeader(http.StatusNoContent)
			return
		}
		next.ServeHTTP(w, r)
	})
}

func generateID() string {
	b := make([]byte, 8)
	_, _ = rand.Read(b)
	return hex.EncodeToString(b)
}

// Package vault defines the SPI for credential and secret storage.
//
// The vault stores sensitive values (API keys, OAuth tokens, service account
// credentials) and injects them into connector execution requests without
// ever exposing them to agents. Agents see only a credential reference ID;
// the vault resolves the actual secret at execution time.
//
// The built-in implementation encrypts secrets at rest using AES-GCM with
// a key stored in the environment. Alternative implementations can delegate
// to HashiCorp Vault, AWS Secrets Manager, GCP Secret Manager, etc.
package vault

import "context"

// Vault stores and retrieves secrets by path.
type Vault interface {
	// Get retrieves a secret by its vault path.
	Get(ctx context.Context, path string) (Secret, error)

	// Put stores a secret at the given path, creating or overwriting it.
	Put(ctx context.Context, path string, value []byte, meta Metadata) error

	// Delete permanently removes a secret.
	Delete(ctx context.Context, path string) error
}

// Secret is a resolved secret value.
type Secret struct {
	Path     string
	Value    []byte
	Metadata Metadata
}

// Metadata carries non-secret attributes stored alongside a secret.
type Metadata struct {
	// Type classifies the credential (e.g. "api_key", "oauth_refresh_token").
	Type        string
	Environment string
	// Labels are arbitrary key-value pairs for organization.
	Labels map[string]string
}

