// Aileron control plane database schema.
// Managed by Atlas (https://atlasgo.io) — declarative, schema-as-code.
//
// Apply with:
//   atlas schema apply --url "postgres://..." --to "file://core/schema/schema.hcl"

schema "public" {}

table "enterprises" {
  schema = schema.public

  column "id" {
    type = varchar(64)
    null = false
  }
  column "name" {
    type = varchar(255)
    null = false
  }
  column "slug" {
    type = varchar(128)
    null = false
  }
  column "plan" {
    type    = varchar(32)
    null    = false
    default = "free"
  }
  column "billing_email" {
    type = varchar(255)
    null = false
  }
  column "sso_required" {
    type    = boolean
    null    = false
    default = false
  }
  column "allowed_auth_providers" {
    type    = text
    null    = false
    default = "[]"
    comment = "JSON array of allowed provider names"
  }
  column "allowed_email_domains" {
    type    = text
    null    = false
    default = "[]"
    comment = "JSON array of allowed email domains"
  }
  column "created_at" {
    type    = timestamptz
    null    = false
    default = sql("now()")
  }
  column "updated_at" {
    type    = timestamptz
    null    = false
    default = sql("now()")
  }

  primary_key {
    columns = [column.id]
  }

  index "idx_enterprises_slug" {
    columns = [column.slug]
    unique  = true
  }
}

table "users" {
  schema = schema.public

  column "id" {
    type = varchar(64)
    null = false
  }
  column "enterprise_id" {
    type = varchar(64)
    null = false
  }
  column "email" {
    type = varchar(255)
    null = false
  }
  column "display_name" {
    type = varchar(255)
    null = false
  }
  column "avatar_url" {
    type    = text
    null    = false
    default = ""
  }
  column "role" {
    type    = varchar(32)
    null    = false
    default = "member"
  }
  column "status" {
    type    = varchar(32)
    null    = false
    default = "active"
  }
  column "auth_provider" {
    type = varchar(64)
    null = false
  }
  column "auth_provider_subject_id" {
    type = varchar(255)
    null = false
  }
  column "last_login_at" {
    type = timestamptz
    null = true
  }
  column "created_at" {
    type    = timestamptz
    null    = false
    default = sql("now()")
  }
  column "updated_at" {
    type    = timestamptz
    null    = false
    default = sql("now()")
  }

  primary_key {
    columns = [column.id]
  }

  foreign_key "fk_users_enterprise" {
    columns     = [column.enterprise_id]
    ref_columns = [table.enterprises.column.id]
    on_delete   = CASCADE
  }

  index "idx_users_email" {
    columns = [column.email]
    unique  = true
