// --- MCP Server credentials ---

func (s *apiServer) SetMCPServerCredential(w http.ResponseWriter, r *http.Request, id string) {
	var req api.SetCredentialRequest
	if err := decodeBody(r, &req); err != nil {
		writeError(w, http.StatusBadRequest, "invalid_request", err.Error())
		return
	}

	ctx := r.Context()

	// Verify server exists.
	srv, err := s.mcpServers.Get(ctx, id)
	if err != nil {
		if isNotFound(err) {
			writeError(w, http.StatusNotFound, "not_found", err.Error())
			return
		}
		writeError(w, http.StatusInternalServerError, "internal_error", err.Error())
		return
	}

	// Store secret in vault.
	vaultPath := "mcp-servers/" + id + "/" + req.EnvVarName
	s.vault.Put(ctx, vaultPath, []byte(req.SecretValue), vault.Metadata{
		Type: "mcp_server_credential",
		Labels: map[string]string{
			"server_id": id,
			"env_var":   req.EnvVarName,
		},
	})

	// Update server config env to reference the vault path.
	envMap := make(map[string]string)
	if srv.Env != nil {
		for k, v := range *srv.Env {
			envMap[k] = v
		}
	}
	envMap[req.EnvVarName] = "vault://" + vaultPath
	srv.Env = &envMap
	now := time.Now().UTC()
	srv.UpdatedAt = &now

	if err := s.mcpServers.Update(ctx, srv); err != nil {
		writeError(w, http.StatusInternalServerError, "internal_error", err.Error())
		return
	}

	writeJSON(w, http.StatusOK, api.SetCredentialResponse{
		EnvVarName: req.EnvVarName,
		Stored:     true,
	})
}

// --- Marketplace ---

func (s *apiServer) ListMarketplaceServers(w http.ResponseWriter, r *http.Request, params api.ListMarketplaceServersParams) {
	ctx := r.Context()

	var query string
	if params.Q != nil {
		query = *params.Q
	}

	servers, err := s.registryClient.Search(ctx, query)
	if err != nil {
		writeError(w, http.StatusBadGateway, "registry_error", err.Error())
		return
	}

	// Build a set of installed registry IDs for enrichment.
	installed, _ := s.mcpServers.List(ctx, store.MCPServerFilter{})
	installedSet := make(map[string]bool, len(installed))
	for _, srv := range installed {
		if srv.RegistryId != nil {
			installedSet[*srv.RegistryId] = true
		}
	}

	// Group registry entries by name, collecting versions. The registry
	// returns entries in release order, so we preserve that ordering and
	// then reverse to get most-recent-first.
	type grouped struct {
		order       int
		description string
		versions    []api.MarketplaceServerVersion
	}
	byName := make(map[string]*grouped)
	var insertOrder int
	for _, srv := range servers {
		ver := api.MarketplaceServerVersion{
			Version: srv.Version,
		}
		var envVars []api.RequiredEnvVar
		for _, pkg := range srv.Packages {
			for _, ev := range pkg.EnvVars {
				envVars = append(envVars, api.RequiredEnvVar{
					Name:        ev.Name,
					Description: &ev.Description,
					Required:    &ev.Required,
				})
			}
		}
		if len(envVars) > 0 {
			ver.RequiredEnvVars = &envVars
		}

		if g, ok := byName[srv.Name]; ok {
			g.versions = append(g.versions, ver)
			// Keep the most recent description (last entry).
			if srv.Description != "" {
				g.description = srv.Description
			}
		} else {
			byName[srv.Name] = &grouped{
				order:       insertOrder,
				description: srv.Description,
				versions:    []api.MarketplaceServerVersion{ver},
			}
			insertOrder++
		}
	}

	// Build response items sorted by first-seen order.
	items := make([]api.MarketplaceServer, 0, len(byName))
	for name, g := range byName {
		// Reverse versions so most recent is first.
		for i, j := 0, len(g.versions)-1; i < j; i, j = i+1, j-1 {
			g.versions[i], g.versions[j] = g.versions[j], g.versions[i]
		}
		ms := api.MarketplaceServer{
			RegistryId: name,
			Name:       name,
		}
		if g.description != "" {
			ms.Description = &g.description
		}
		isInstalled := installedSet[name]
		ms.Installed = &isInstalled
		ms.Versions = &g.versions
		items = append(items, ms)
	}
	// Stable sort by insertion order.
	sort.Slice(items, func(i, j int) bool {
		return byName[items[i].Name].order < byName[items[j].Name].order
	})

	writeJSON(w, http.StatusOK, map[string]any{"items": items})
}

func (s *apiServer) InstallMarketplaceServer(w http.ResponseWriter, r *http.Request, registryId string) {
	ctx := r.Context()

	srv, err := s.registryClient.Get(ctx, registryId)
	if err != nil {
		writeError(w, http.StatusBadGateway, "registry_error", err.Error())
		return
	}
	if srv == nil {
		writeError(w, http.StatusNotFound, "not_found", "server not found in registry: "+registryId)
		return
	}

	// Derive command from the best available package.
	command, envVars := deriveCommand(srv)

	id := "mcp_" + s.newID()
	now := time.Now().UTC()
	stopped := api.MCPServerConfigStatusStopped
	local := api.Local
	config := api.MCPServerConfig{
		Id:         &id,
		Name:       srv.Name,
		Command:    command,
		Status:     &stopped,
		Mode:       &local,
		RegistryId: &registryId,
		CreatedAt:  &now,
	}
	if srv.Description != "" {
		config.Description = &srv.Description
	}
	if srv.Version != "" {
		config.Version = &srv.Version
	}

	// Pre-populate env map with empty values for required env vars.
	if len(envVars) > 0 {
		envMap := make(map[string]string, len(envVars))
		for _, ev := range envVars {
			envMap[ev.Name] = ""
		}
		config.Env = &envMap
	}

	if err := s.mcpServers.Create(ctx, config); err != nil {
		writeError(w, http.StatusInternalServerError, "internal_error", err.Error())
		return
	}

	// Build required credentials list.
	var reqCreds []api.RequiredEnvVar
	for _, ev := range envVars {
		reqCreds = append(reqCreds, api.RequiredEnvVar{
			Name:        ev.Name,
			Description: &ev.Description,
			Required:    &ev.Required,
		})
	}

	result := api.InstallResult{
		Server: config,
	}
	if len(reqCreds) > 0 {
		result.RequiredCredentials = &reqCreds
	}

	writeJSON(w, http.StatusCreated, result)
}

// deriveCommand picks the best package from a registry server and returns
// the command array and required env vars.
func deriveCommand(srv *registry.RegistryServer) ([]string, []registry.EnvVar) {
	// Prefer npm packages (most common for MCP servers).
	for _, pkg := range srv.Packages {
		if pkg.RegistryType == "npm" {
			cmd := []string{"npx", "-y", pkg.Name}
			if pkg.Runtime.Args != nil {
				cmd = append(cmd, pkg.Runtime.Args...)
			}
			return cmd, pkg.EnvVars
		}
	}

	// Fall back to any package with a runtime command.
	for _, pkg := range srv.Packages {
		if pkg.Runtime.Command != "" {
			cmd := []string{pkg.Runtime.Command}
			cmd = append(cmd, pkg.Runtime.Args...)
			return cmd, pkg.EnvVars
		}
	}

	// Last resort: use the server name as the command.
	return []string{srv.Name}, nil
}

// Package app wires together the Aileron control plane components and exposes
// them as an http.Handler. It is imported by the standalone server binary and
// the MCP server's embedded mode.
package app

import (
	"context"
	"log/slog"
	"net/http"
	"os"
	"time"

	api "github.com/ALRubinger/aileron/core/api/gen"
	"github.com/ALRubinger/aileron/core/approval"
	"github.com/ALRubinger/aileron/core/auth"
	googleauth "github.com/ALRubinger/aileron/core/auth/google"
	"github.com/ALRubinger/aileron/core/config"
	"github.com/ALRubinger/aileron/core/connector"
	googlecalendar "github.com/ALRubinger/aileron/core/connector/calendar/google"
	"github.com/ALRubinger/aileron/core/connector/git/github"
	"github.com/ALRubinger/aileron/core/connector/payments/stripe"
	"github.com/ALRubinger/aileron/core/notify"
	"github.com/ALRubinger/aileron/core/policy"
	mcpreg "github.com/ALRubinger/aileron/core/registry"
	"github.com/ALRubinger/aileron/core/store/mem"
	"github.com/ALRubinger/aileron/core/store/postgres"
	"github.com/ALRubinger/aileron/core/vault"
	"github.com/google/uuid"
)

// NewHandler creates a fully-wired Aileron control plane HTTP handler with
// in-memory stores, seeded policies, and registered connectors.
func NewHandler(log *slog.Logger) (http.Handler, error) {
	ctx := context.Background()

	// --- In-memory stores ---
	intentStore := mem.NewIntentStore()
	approvalStore := mem.NewApprovalStore()
	policyStore := mem.NewPolicyStore()
	grantStore := mem.NewGrantStore()
	executionStore := mem.NewExecutionStore()
	connectorStore := mem.NewConnectorStore()
	mcpServerStore := mem.NewMCPServerStore()
	credentialStore := mem.NewCredentialStore()
	fundingSourceStore := mem.NewFundingSourceStore()
	traceStore := mem.NewTraceStore()

	// --- Connector registry ---
	registry := connector.NewRegistry()
	registry.Register(ctx, stripe.New())
	registry.Register(ctx, googlecalendar.New())
	registry.Register(ctx, github.New())

	// --- Vault ---
	v := vault.NewMemVault()
	if token := os.Getenv("GITHUB_TOKEN"); token != "" {
		v.Put(ctx, "connectors/github/default", []byte(token), vault.Metadata{
			Type: "api_key",
			Labels: map[string]string{
				"connector": "github",
			},
		})
		log.Info("seeded GitHub token into vault")
	}

	// --- Policy engine ---
	policyEngine := policy.NewRuleEngine(policyStore)

	if err := policy.SeedPolicies(ctx, policyStore); err != nil {
		return nil, err
	}
	log.Info("seeded default policies")

	// --- Approval orchestrator ---
	idGen := func() string { return uuid.New().String() }
	orchestrator := approval.NewInMemoryOrchestrator(approvalStore, idGen)

	// --- MCP Registry client ---
	registryClient := mcpreg.NewClient(nil, log)
	if interval := os.Getenv("REGISTRY_REFRESH_INTERVAL"); interval != "" {
		if d, err := time.ParseDuration(interval); err == nil {
			registryClient = registryClient.WithRefreshInterval(d)
			log.Info("registry refresh interval overridden", "interval", d)
		} else {
			log.Warn("invalid REGISTRY_REFRESH_INTERVAL, using default", "value", interval, "error", err)
		}
	}
	registryClient.Start(ctx)

	// --- Notifier ---
	notifier := notify.NewLogNotifier(log)

	// --- HTTP handler ---
	mux := http.NewServeMux()

	server := &apiServer{
		log:            log,
		registry:       registry,
		policyEngine:   policyEngine,
		orchestrator:   orchestrator,
		vault:          v,
		notifier:       notifier,
		intents:        intentStore,
		approvals:      approvalStore,
		policies:       policyStore,
		grants:         grantStore,
		executions:     executionStore,
		connectors:     connectorStore,
		mcpServers:     mcpServerStore,
		registryClient: registryClient,
		credentials:    credentialStore,
		fundingSources: fundingSourceStore,
		traces:         traceStore,
		newID:          idGen,
	}
	api.HandlerFromMux(server, mux)

	registerDocsRoutes(mux)

	// --- Auth (optional — enabled when AILERON_DATABASE_URL is set) ---
	authCfg, err := config.LoadAuthConfig()
	if err != nil {
		return nil, err
	}

	// Middleware chain: CORS -> request ID -> logging -> [auth] -> routes.
	var handler http.Handler = mux

	if authCfg.AuthEnabled() {
		db, err := postgres.NewDB(ctx, authCfg.DatabaseURL)
		if err != nil {
			return nil, err
		}
		log.Info("connected to PostgreSQL")

		enterpriseStore := postgres.NewEnterpriseStore(db)
		userStore := postgres.NewUserStore(db)
		sessionStore := postgres.NewSessionStore(db)

		tokenIssuer := auth.NewTokenIssuer(
			[]byte(authCfg.JWTSigningKey),
			authCfg.JWTIssuer,
			authCfg.AccessTokenTTL,
		)

		authRegistry := auth.NewRegistry()
		if authCfg.GoogleEnabled() {
			authRegistry.Register(googleauth.New(
				authCfg.GoogleClientID,
				authCfg.GoogleClientSecret,
				authCfg.GoogleRedirectURL,
			))
			log.Info("registered Google OAuth provider")
		}

		enforcer := auth.NewStoreEnforcer(enterpriseStore)

		authHandler := auth.NewHandler(auth.HandlerConfig{
			Log:         log,
			Registry:    authRegistry,
			Enforcer:    enforcer,
			Issuer:      tokenIssuer,
			Users:       userStore,
			Enterprises: enterpriseStore,
			Sessions:    sessionStore,
			NewID:       idGen,
			UIRedirect:  authCfg.UIRedirectURL,
			RefreshTTL:  authCfg.RefreshTokenTTL,
		})
		authHandler.RegisterRoutes(mux)

		skipPaths := map[string]bool{
			"/v1/health": true,
		}
		handler = auth.Middleware(tokenIssuer, skipPaths)(handler)
		log.Info("auth middleware enabled")
	}

	handler = loggingMiddleware(log, handler)
	handler = requestIDMiddleware(handler)
	handler = corsMiddleware(handler)

	return handler, nil
}

