		Plan:         model.EnterprisePlanFree,
		Personal:     personal,
		BillingEmail: identity.Email,
		CreatedAt:    now,
		UpdatedAt:    now,
	}
	if err := h.enterprises.Create(ctx, enterprise); err != nil {
